def choose_move(observation):
    w = int(observation.get("grid_width", 8) or 8)
    h = int(observation.get("grid_height", 8) or 8)
    s = observation.get("self_position") or [0, 0]
    o = observation.get("opponent_position") or [0, 0]
    sx, sy = int(s[0]), int(s[1])
    ox, oy = int(o[0]), int(o[1])

    obstacles = set()
    for b in observation.get("obstacles") or []:
        if b is not None and len(b) >= 2:
            bx, by = int(b[0]), int(b[1])
            if 0 <= bx < w and 0 <= by < h:
                obstacles.add((bx, by))

    resources = []
    for r in observation.get("resources") or []:
        if r is not None and len(r) >= 2:
            rx, ry = int(r[0]), int(r[1])
            if 0 <= rx < w and 0 <= ry < h and (rx, ry) not in obstacles:
                resources.append((rx, ry))

    dirs = [(-1, -1), (-1, 0), (-1, 1), (0, -1), (0, 0), (0, 1), (1, -1), (1, 0), (1, 1)]

    def dist2(ax, ay, bx, by):
        dx = ax - bx
        dy = ay - by
        return dx * dx + dy * dy

    def valid(nx, ny):
        return 0 <= nx < w and 0 <= ny < h and (nx, ny) not in obstacles

    best = None
    bestv = None
    bestod = None
    if not resources:
        tx, ty = (0, 0) if (sx + sy) > (w + h - 2) else (w - 1, h - 1)
        for dx, dy in dirs:
            nx, ny = sx + dx, sy + dy
            if not valid(nx, ny):
                continue
            v = dist2(nx, ny, tx, ty)
            od = dist2(nx, ny, ox, oy)
            if best is None or v < bestv or (v == bestv and od > bestod):
                best = (dx, dy)
                bestv = v
                bestod = od
        return list(best if best is not None else [0, 0])

    for dx, dy in dirs:
        nx, ny = sx + dx, sy + dy
        if not valid(nx, ny):
            continue
        dmin = None
        odmin = None
        for rx, ry in resources:
            d = dist2(nx, ny, rx, ry)
            if dmin is None or d < dmin:
                dmin = d
        for rx, ry in resources:
            d = dist2(ox, oy, rx, ry)
            if odmin is None or d < odmin:
                odmin = d
        adv = (odmin - dmin) if odmin is not None and dmin is not None else 0
        oppd = dist2(nx, ny, ox, oy)
        v = (-adv, dmin, -oppd)
        if best is None or v < bestv:
            best = (dx, dy)
            bestv = v

    return list(best if best is not None else [0, 0])

